        for (int i = 1; i <= n; i++) {
            graph[i] = new ArrayList<>();
        }
        for (int[] dislike : dislikes) {
            graph[dislike[0]].add(dislike[1]);
            graph[dislike[1]].add(dislike[0]);
        }
        boolean[] color = new boolean[n + 1];
        for (int i = 1; i <= n; i++) {
            if (!color[i]) {
                if (!dfs(graph, color, i, 1)) {
                    return false;
                }
            }
        }
        return true;
    }
    private boolean dfs(List<Integer>[] graph, boolean[] color, int node, int c) {
        color[node] = c;
        for (int neighbor : graph[node]) {
            if (!color[neighbor]) {
                if (!dfs(graph, color, neighbor, 3 - c)) {
                    return false;
                }
            } else if (color[neighbor] == c) {
                return false;
            }
        }
        return true;
    }
}
